import React, { useState, useEffect, useMemo, useRef } from 'react';

const Icon = ({ name }) => {
  const icons = {
    telegram: <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm4.64 6.8c-.15 1.58-.8 5.42-1.13 7.19-.14.75-.42 1-.68 1.03-.58.05-1.02-.38-1.58-.75-.88-.58-1.38-.94-2.23-1.5-.99-.65-.35-1.01.22-1.59.15-.15 2.71-2.48 2.76-2.69.01-.03.01-.14-.07-.2-.08-.06-.19-.04-.27-.02-.11.02-1.93 1.23-5.46 3.62-.51.35-.98.53-1.39.52-.46-.01-1.33-.26-1.98-.48-.8-.27-1.43-.42-1.37-.89.03-.25.38-.51 1.03-.78 4.04-1.76 6.74-2.92 8.09-3.48 3.85-1.6 4.64-1.88 5.17-1.89.11 0 .37.03.54.17.14.12.18.28.2.45-.02.07-.02.13-.03.19z"/>,
    phone: <path d="M22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07 19.5 19.5 0 0 1-6-6 19.79 19.79 0 0 1-3.07-8.67A2 2 0 0 1 4.11 2h3a2 2 0 0 1 2 1.72 12.84 12.84 0 0 0 .7 2.81 2 2 0 0 1-.45 2.11L8.09 9.91a16 16 0 0 0 6 6l1.27-1.27a2 2 0 0 1 2.11-.45 12.84 12.84 0 0 0 2.81.7A2 2 0 0 1 22 16.92z"/>
  };
  return <svg viewBox="0 0 24 24" width="18" height="18" fill="currentColor">{icons[name]}</svg>;
};

const ProjectCard = ({ project, index }) => {
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const [isHovering, setIsHovering] = useState(false);

  const handleMouseMove = (e) => {
    const rect = e.currentTarget.getBoundingClientRect();
    setMousePos({ x: e.clientX - rect.left, y: e.clientY - rect.top });
  };

  return (
    <div 
      className="project-card" 
      style={{ animationDelay: `${index * 0.15}s` }}
      onMouseMove={handleMouseMove}
      onMouseEnter={() => setIsHovering(true)}
      onMouseLeave={() => setIsHovering(false)}
    >
      <div className="img-container">
        <img src={project.img} alt={project.title} />
        <div 
          className="magnetic-badge"
          style={{ 
            left: mousePos.x, 
            top: mousePos.y,
            opacity: isHovering ? 1 : 0,
            transform: `translate(-50%, -50%) scale(${isHovering ? 1 : 0.5})`
          }}
        >
          смотреть
        </div>
      </div>
      <div className="project-details">
        <div className="reveal-box">
          <span className="category-tag">{project.cat}</span>
          <h3>{project.title}</h3>
        </div>
        <span className="year">{project.year}</span>
      </div>
    </div>
  );
};

const App = () => {
  const [filter, setFilter] = useState('Все');
  const [isScrolled, setIsScrolled] = useState(false);
  const [showArchive, setShowArchive] = useState(false);

  const categories = ['Все', 'Айдентика', 'Логотипы', 'Веб-дизайн', 'Печатная графика'];
  const projects = useMemo(() => ({
    featured: [
      { id: 'f1', title: "Проект айдентики", cat: "Айдентика", year: 2025, img: "https://images.unsplash.com/photo-1626785774573-4b799315345d?auto=format&fit=crop&q=80&w=800" },
      { id: 'f2', title: "Веб-интерфейс", cat: "Веб-дизайн", year: 2025, img: "https://images.unsplash.com/photo-1551288049-bbbda5366392?auto=format&fit=crop&q=80&w=800" },
      { id: 'f3', title: "Логотип и стиль", cat: "Логотипы", year: 2025, img: "https://images.unsplash.com/photo-1572044162444-ad60f128bde2?auto=format&fit=crop&q=80&w=800" },
    ],
    archive: [
      { id: 'a1', title: "Архивный кейс", cat: "Логотипы", year: 2024, img: "https://images.unsplash.com/photo-1614850523296-d8c1af93d400?auto=format&fit=crop&q=80&w=800" },
    ]
  }), []);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const scrollTo = (id) => {
    const el = document.getElementById(id);
    if (el) window.scrollTo({ top: el.offsetTop - 120, behavior: 'smooth' });
  };

  return (
    <div className="app-container">
      <div className="bg-elements">
        <div className="glow-1"></div>
        <div className="glow-2"></div>
      </div>

      <header className={`nav-header ${isScrolled ? 'shrunk' : ''}`}>
        <div className="nav-inner">
          <div className="logo-group">
            <div className="dot"></div>
            <span>АЛЕКСАНДРА БЛАГОДАТСКИХ</span>
          </div>
          <nav>
            <button onClick={() => scrollTo('projects')}>работы</button>
            <button onClick={() => scrollTo('contact')}>связь</button>
          </nav>
        </div>
      </header>

      <section id="about" className="hero">
        <div className="hero-content">
          <h1 className="title-reveal">
            <span>Создаю <i className="accent">эстетичный</i></span>
            <span>и продуманный дизайн.</span>
          </h1>
          <p className="hero-desc">
            Разрабатываю визуальные решения для бизнеса: от логотипов и систем айдентики 
            до веб-интерфейсов и макетов в печать.
          </p>
        </div>

        <div className="filter-pill-container">
          {categories.map(cat => (
            <button 
              key={cat} 
              onClick={() => setFilter(cat)}
              className={`pill ${filter === cat ? 'active' : ''}`}
            >
              {cat}
            </button>
          ))}
        </div>
      </section>

      <main id="projects" className="work-section">
        <div className="grid">
          {projects.featured.filter(p => filter === 'Все' || p.cat === filter).map((project, i) => (
            <ProjectCard key={project.id} project={project} index={i} />
          ))}
        </div>

        <div className="archive-box">
          <button className="minimal-btn" onClick={() => setShowArchive(!showArchive)}>
            {showArchive ? '[ свернуть ]' : '[ смотреть архив ]'}
          </button>
        </div>
      </main>

      <footer id="contact" className="footer">
        <div className="footer-wrap">
          <h2 className="footer-title">Есть проект?</h2>
          <div className="footer-links">
            <a href="tel:+79639960003" className="mag-link">8 963 996 00 03 <span>↗</span></a>
            <a href="https://t.me/renraie" target="_blank" className="mag-link">Telegram <span>↗</span></a>
          </div>
          <div className="footer-bottom">
            <span>© 2024—2026</span>
            <div className="status-badge">Available for work</div>
          </div>
        </div>
      </footer>

      <style>{`
        :root {
          --dark: #0a0a0b;
          --accent: #ffb3d9;
          --gray: #808085;
          --white: #ffffff;
        }

        body {
          margin: 0; background: var(--dark); color: var(--white);
          font-family: 'Inter', -apple-system, sans-serif;
          overflow-x: hidden; -webkit-font-smoothing: antialiased;
        }

        .bg-elements {
          position: fixed; inset: 0; z-index: -1; pointer-events: none;
        }
        .glow-1 { position: absolute; top: -10%; right: -5%; width: 40vw; height: 40vw; background: radial-gradient(circle, rgba(255,179,217,0.05) 0%, transparent 70%); filter: blur(60px); }

        .nav-header {
          position: fixed; top: 0; left: 0; width: 100%; z-index: 1000;
          padding: 40px 0; transition: 0.5s cubic-bezier(0.2, 1, 0.3, 1);
        }
        .nav-header.shrolled, .nav-header.shrunk { padding: 20px 0; background: rgba(10,10,11,0.8); backdrop-filter: blur(20px); }
        .nav-inner { max-width: 1400px; margin: 0 auto; display: flex; justify-content: space-between; align-items: center; padding: 0 50px; }

        .logo-group { display: flex; align-items: center; gap: 12px; font-weight: 600; font-size: 13px; letter-spacing: 0.1em; }
        .dot { width: 8px; height: 8px; background: var(--accent); border-radius: 50%; box-shadow: 0 0 15px var(--accent); }

        nav button { background: none; border: none; color: var(--gray); font-size: 12px; text-transform: uppercase; letter-spacing: 0.2em; cursor: pointer; transition: 0.3s; margin-left: 40px; }
        nav button:hover { color: var(--white); transform: translateY(-2px); }

        .hero { padding: 250px 50px 100px; max-width: 1400px; margin: 0 auto; }
        .title-reveal { font-size: clamp(40px, 7vw, 90px); font-weight: 300; line-height: 1.1; margin-bottom: 40px; }
        .title-reveal span { display: block; overflow: hidden; }
        .accent { font-style: italic; color: var(--accent); font-family: 'Playfair Display', serif; }
        .hero-desc { color: var(--gray); font-size: 20px; max-width: 600px; line-height: 1.6; animation: fadeIn 1s 0.5s both; }

        .filter-pill-container { display: flex; gap: 10px; margin-top: 60px; flex-wrap: wrap; }
        .pill { padding: 12px 24px; border-radius: 40px; border: 1px solid rgba(255,255,255,0.1); background: rgba(255,255,255,0.03); color: var(--gray); cursor: pointer; transition: 0.4s; font-size: 12px; }
        .pill.active { background: var(--white); color: var(--dark); border-color: var(--white); }

        .work-section { max-width: 1400px; margin: 0 auto; padding: 100px 50px; }
        .grid { display: grid; grid-template-columns: 1fr 1fr; gap: 100px 60px; }

        .project-card { opacity: 0; animation: fadeInUp 1s forwards; cursor: none; }
        .project-card:nth-child(even) { transform: translateY(80px); }

        .img-container { position: relative; aspect-ratio: 16/10; border-radius: 24px; overflow: hidden; background: #151517; }
        .img-container img { width: 100%; height: 100%; object-fit: cover; transition: 1.5s cubic-bezier(0.2, 1, 0.3, 1); }
        .project-card:hover img { transform: scale(1.08); }

        .magnetic-badge {
          position: absolute; width: 100px; height: 100px; background: var(--white); color: var(--dark);
          border-radius: 50%; display: flex; align-items: center; justify-content: center;
          font-size: 12px; font-weight: 600; text-transform: uppercase;
          pointer-events: none; z-index: 10; transition: opacity 0.3s, transform 0.1s linear;
        }

        .project-details { margin-top: 30px; display: flex; justify-content: space-between; align-items: flex-end; }
        .category-tag { font-size: 11px; text-transform: uppercase; color: var(--accent); letter-spacing: 0.1em; }
        .project-details h3 { font-size: 32px; font-family: 'Playfair Display', serif; font-weight: 400; margin: 10px 0 0; }
        .year { color: var(--gray); font-size: 12px; }

        .archive-box { text-align: center; margin-top: 150px; }
        .minimal-btn { background: none; border: none; color: var(--gray); text-transform: uppercase; letter-spacing: 0.3em; cursor: pointer; transition: 0.3s; }
        .minimal-btn:hover { color: var(--accent); }

        .footer { background: #050506; padding: 150px 50px 50px; border-top: 1px solid rgba(255,255,255,0.05); }
        .footer-wrap { max-width: 1400px; margin: 0 auto; }
        .footer-title { font-size: clamp(40px, 6vw, 80px); margin-bottom: 60px; font-weight: 300; }
        .footer-links { display: flex; flex-direction: column; gap: 20px; }
        .mag-link { font-size: 40px; text-decoration: none; color: var(--white); transition: 0.4s; display: flex; align-items: center; gap: 20px; }
        .mag-link span { color: var(--accent); opacity: 0; transform: translate(-20px, 20px); transition: 0.4s; }
        .mag-link:hover { padding-left: 30px; color: var(--accent); }
        .mag-link:hover span { opacity: 1; transform: translate(0,0); }

        .footer-bottom { margin-top: 100px; padding-top: 40px; border-top: 1px solid rgba(255,255,255,0.05); display: flex; justify-content: space-between; font-size: 11px; color: var(--gray); text-transform: uppercase; letter-spacing: 0.2em; }
        .status-badge { color: #00ffaa; display: flex; align-items: center; gap: 8px; }
        .status-badge::before { content: ''; width: 6px; height: 6px; background: #00ffaa; border-radius: 50%; box-shadow: 0 0 10px #00ffaa; }

        @keyframes fadeInUp {
          from { opacity: 0; transform: translateY(60px); }
          to { opacity: 1; transform: translateY(0); }
        }
        @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }

        @media (max-width: 900px) {
          .grid { grid-template-columns: 1fr; }
          .project-card:nth-child(even) { transform: translateY(0); }
          .nav-inner { padding: 0 20px; }
          .hero { padding-top: 150px; }
          .mag-link { font-size: 24px; }
        }
      `}</style>
    </div>
  );
};

export default App;
